INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028542e3c98b094176614a', '房间卫生干净，环境不错，服务贴心', '["https://dimg04.c-ctrip.com/images/0235x12000eecm3yq22E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000eecxw256C9B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-09', '花园双床房', '双床房', '家庭亲子', 16, 0, 13, 4, '["卫生状况","整体满意度","前台服务"]'::jsonb, '卫生状况', '整体满意度', '前台服务'),
('68028542e3c98b094176614b', '广州花园酒店地处广州市中心的位置，酒店大气，环境优美，服务人员热情，主动。床铺舒适，超性价比的价格值的点赞', '["https://dimg04.c-ctrip.com/images/0231x12000djiqxf3126B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-30', '城央绿意双床房', '双床房', '商务出差', 53, 0, 18, 7, '["整体满意度","性价比"]'::jsonb, '整体满意度', '性价比', NULL),
('68028542e3c98b094176614c', '办入住的时候 立即享受了房间升级的优惠， 花了很少的钱 入住了新装修的套房， 漂亮舒适整洁， 服务是全世界最棒的！ 
还和朋友一起下午茶 ， 遇到了很多美女网红在拍照打卡， 虽然我是个女的 感觉也挺养眼！ 金碧辉煌的大堂 ， 非常契合岭南文化的韵味！', '["https://dimg04.c-ctrip.com/images/0230c12000cykdb1iBD54_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000cyks5ba5AD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000cykrk0n2274_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-17', '花园大床房', '大床房', '朋友出游', 125, 0, 3, 8, '["前台服务","整体满意度","性价比"]'::jsonb, '前台服务', '整体满意度', '性价比'),
('68028542e3c98b094176614d', '因为团了两份一晚的套餐，忘记复制了，竟然要写两遍哈哈??我不想写两遍～这篇就看图说话吧
图1花园瀑布，好看的值得一逛里面还有很多小景点出片的，就有种影楼拍照的密集布景～很嗲
图2每天晚上回去会有小甜品，因为回去都太晚了～所以也不知道是下午茶还是夜宵～我估计应该是下午茶？哈哈
图3??是酒店2楼荔湾艇的奶茶！虽然不便宜～和茶位费一样贵～但真的很可爱～很别致的小狮子～我建议茶可以不喝～小狮子一定要点哦～对了，吃到一半会有人说书～蛮有意思的', '["https://dimg04.c-ctrip.com/images/0236z12000d1fb1qaB062_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000d1f6grc8181_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000d1f9nyk1F6D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-01-25', '红棉大床套房', '套房', '家庭亲子', 219, 0, 31, 7, '["餐饮设施","公共设施","整体满意度"]'::jsonb, '餐饮设施', '公共设施', '整体满意度'),
('68028542e3c98b094176614e', '绝对是五星的性价比，服务超好，内部环境很干净', '["https://dimg04.c-ctrip.com/images/0235612000e56io4903D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000e56b84x8177_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000e56vphqB6E8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-24', '城央绿意双床房', '双床房', '代人预订', 22, 0, 6, 5, '["性价比","整体满意度","卫生状况"]'::jsonb, '性价比', '整体满意度', '卫生状况'),
('68028542e3c98b094176614f', '服务周到，房间整洁，开心之旅！', '["https://dimg04.c-ctrip.com/images/0233812000edryn8e80CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000edrybs08CC6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000edryyld0851_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-08', '红棉双床套房', '套房', '朋友出游', 15, 0, 13, 4, '["整体满意度","客房服务","卫生状况"]'::jsonb, '整体满意度', '客房服务', '卫生状况'),
('68028542e3c98b0941766150', '酒店服务周到，宾至如归', '["https://dimg04.c-ctrip.com/images/0230b12000edry10142E6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000edrx8157DC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000edrybmzC955_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-08', '红棉双床套房', '套房', '家庭亲子', 11, 0, 13, 3, '["前台服务","客房服务"]'::jsonb, '前台服务', '客房服务', NULL),
('68028542e3c98b0941766151', '一进大厅就震撼到了，壮观啊！不愧白金五星酒店，
设施：齐全
卫生：很干净
环境：非常好
服务：很到位，就是得排队
内部有想陈旧了，应该再装修一下', '["https://dimg04.c-ctrip.com/images/0232z12000d6if1af5C0E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000d6ikgkj3B99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000d6iw0uh406A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '花园双床房', '双床房', '家庭亲子', 72, 0, 10, 6, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68028542e3c98b0941766152', '非常满意，很棒的旅程！', '["https://dimg04.c-ctrip.com/images/0231y12000e6ppugc6A1E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000e6pi23z52AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000e6p7m1mC0CE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-27', '花园大床房', '大床房', '其他', 11, 0, 3, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b0941766153', '房间非常好，大厅富丽堂皇，但是内部并没有那么富丽堂皇，服务也还可以
设施：有些旧了
卫生：很好，配得上五星
环境：很好
服务：很好！', '["https://dimg04.c-ctrip.com/images/0230q12000d8i6vd4AE8C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000d8i6i0m4E75_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000d8i6zgaEBC7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-18', '花园双床房', '双床房', '家庭亲子', 66, 0, 10, 6, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68028542e3c98b0941766154', '因为觉得住的还挺好所以续房一天，酒店正好重新装修一部分房间，让我们搬到粤韵房了，这个房间更新一些，床也更舒适，酒店早餐还不错，还赠送了水果，小小瑕疵就是退房把车开上来装行李的时候，我们打算停在门口装，礼宾部外面的接待员让我停到对面的专用车位，绕了一圈开过去之后我请其他的服务员把行李车送到车子旁边，他张嘴一句，你能把车开到门口吗？??，所以不知道到底要在哪里装，有没有一个执行标准呢？小小瑕疵不掩玉，对酒店其他服务还都是很满意的。', '["https://dimg04.c-ctrip.com/images/0233e12000cseympoBFBE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000cses5s878E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000csf1umgF6F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000cseu3w32483_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000cseitsd4534_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000cseu3pfBF6B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-24', '城央绿意双床房', '双床房', '家庭亲子', 215, 0, 79, 8, '["房间设施","整体满意度","前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务'),
('68028542e3c98b0941766155', '细致服务，满意', '["https://dimg04.c-ctrip.com/images/0233m324x8v34es8cDDC5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z324x8v34tsla6009_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s324x8v3r6zj92291_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-03', '花园大床房', '大床房', '商务出差', 7, 0, 16, 3, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68028542e3c98b0941766156', '非常满意的酒店，入住以来处处满意，房间有些旧，但能满足需求，服务人员入微亲切，那么冷的天电梯小姐穿的单薄跑到室外指引我们停车库方向。还帮我们升级了红棉双床房，除了床有些软，都很喜欢。', '["https://dimg04.c-ctrip.com/images/0235a12000cs68levA63B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000cs6cjt2BEB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000cs651f40F6D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000cs6eg3fEC84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000cs6eg3hD001_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000cs6426x72BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000cs6a49lAA3A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000cs65xlm65E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000cs68966EEA9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-22', '城央绿意双床房', '双床房', '家庭亲子', 91, 0, 79, 8, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68028542e3c98b0941766157', '设施：比较怀旧复古小香港的那种风格
环境：挺舒服的
卫生：干净整洁

服务：很好总体来说  问了意见后 我建议水太少 马上增加了矿泉水数量 很好', '["https://dimg04.c-ctrip.com/images/0235h12000d23onf5195A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000d23uj5g3C0E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-27', '花园双床房', '双床房', '独自旅行', 72, 0, 22, 6, '["整体满意度","客房服务","卫生状况"]'::jsonb, '整体满意度', '客房服务', '卫生状况'),
('68028542e3c98b0941766158', '大堂富丽堂皇，像一座艺术殿堂，房间干净卫生整齐，服务态度好。瀑布餐厅漂亮值得打卡，四楼酒店博物馆讲述了中国酒店的发展史', '["https://dimg04.c-ctrip.com/images/0232f12000d6u6fhs2768_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000d6u22r564DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000d6u1iaw5B00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-13', '花园双床房', '双床房', '家庭亲子', 59, 0, 19, 7, '["整体满意度","卫生状况","公共设施"]'::jsonb, '整体满意度', '卫生状况', '公共设施'),
('68028542e3c98b0941766159', 'Joyce 为我们免费升级的套房，?非常不错，人也漂亮，英语流利', '["https://dimg04.c-ctrip.com/images/0231712000di2k5bo6032_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000di2m1y36243_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000di2uqdtCEBE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000di2e70d2825_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000di2mv6lCB16_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000di2foi3CA64_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000di2mm0rB63E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000di28k7gE246_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-25', '花园大床房', '大床房', '商务出差', 32, 0, 8, 6, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68028542e3c98b094176615a', '没有住到自己想住的房间（原已订房）办理入住时，碰到一个业务不熟的服务员（三间房办理了一个多小时）但还是没有办理完整的入住手续，给我们后续入住带来了很大的麻烦（餐饮、房卡）', '["https://dimg04.c-ctrip.com/images/0233s12000cspnj4oC066_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000cspxe751FDC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000cspqs7u48CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-12-25', '红棉大床套房', '套房', '家庭亲子', 85, 0, 36, 7, '["前台服务","退房/入住效率"]'::jsonb, '前台服务', '退房/入住效率', NULL),
('68028542e3c98b094176615b', '上次住感觉还可以，这次真的太差了尤其是卫生真的好差，房间有股浓臭味，地毯也好脏。一般在哪里酒店住套房房间都会准备好水果，楼下的工程噪音夜晚通宵吵得没办法睡觉。大堂穿闪片旗袍的礼仪有个女儿脾气太拽了一点礼貌没有。', '["https://dimg04.c-ctrip.com/images/0231p12000couxerd3767_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-12-06', '花园行政大床套房', '套房', '商务出差', 105, 0, 44, 8, '["卫生状况","安静程度","客房服务"]'::jsonb, '卫生状况', '安静程度', '客房服务'),
('68028542e3c98b094176615c', '停车很方便，有充电桩，设施服务完善，交通方便，客房部徐经理贴心的赠送了水果和儿童洗漱用品.', '["https://dimg04.c-ctrip.com/images/0231912000ig0v6r64CC7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000ig0jkroFE42_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-10', '花园双床房', '双床房', '情侣出游', 45, 0, 19, 7, '["公共设施","交通便利性","客房服务"]'::jsonb, '公共设施', '交通便利性', '客房服务'),
('68028542e3c98b094176615d', '没有住到自己想住的房间（原已订房）办理入住时，碰到一个业务不熟的服务员（三间房办理了一个多小时）但还是没有办理完整的入住手续，给我们后续入住带来了很大的麻烦（餐饮房卡）', '["https://dimg04.c-ctrip.com/images/0232u12000cspo6di63B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000cspxrbb7421_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000cspyh02ABF7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-12-25', '红棉大床套房', '套房', '家庭亲子', 84, 0, 36, 7, '["前台服务","退房/入住效率"]'::jsonb, '前台服务', '退房/入住效率', NULL),
('68028542e3c98b094176615e', '为了满足父母情怀选择了这家老牌酒店，其实我是不喜欢住这种的，外国人不少，整个大堂叽叽呱呱的很吵，餐厅吃了性价比也是挺低的，味道并没有很惊艳', '["https://dimg04.c-ctrip.com/images/0231y12000dlmsumoAA64_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000dlmwr8778DC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000dlmteb5F3D4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-04-06', '花园双床房', '双床房', '家庭亲子', 69, 0, 8, 7, '["安静程度","性价比","餐饮设施"]'::jsonb, '安静程度', '性价比', '餐饮设施'),
('68028542e3c98b0941766161', '设施：老酒店但改造后还是一如既往舒适。
卫生：干净。
环境：大堂一如既往的热闹，房间则安静。
服务：比以往增加了很多外籍员工，英语国语粤语切换自如，很有国际范。
其它∶泳池，干蒸超级点赞，早餐能吃到纳豆，是值得推荐的酒店。', '["https://dimg04.c-ctrip.com/images/0200z12000cp3r530610C_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0234t12000cp3jh42A2C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000cp3cr5a2D62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000cp35h8xC0CD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-08', '花园大床房', '大床房', '商务出差', 111, 0, 42, 8, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施'),
('68028542e3c98b0941766162', '一走进大厅，高端大气上档次，酒店还有一个博物馆，可以去逛逛，出行很方便，酒店出来就是地铁淘金站，总体感觉很不错', '["https://dimg04.c-ctrip.com/images/0230c12000d5qvdg4C77B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000d5qid7f9669_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000d5quj3i164B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-08', '花园双床房', '双床房', '家庭亲子', 55, 0, 29, 7, '["交通便利性","整体满意度","公共设施"]'::jsonb, '交通便利性', '整体满意度', '公共设施'),
('68028542e3c98b0941766163', '真正的民旅品牌，超白金酒店。因为是在广交会期间，人山人海，但配备的服务员多，秩序井然。礼宾部的讲解人员小陈热情主动，认真讲解酒店的前世今生。由于外国人太多，酒店的香薰味太浓，引起嗓子不舒服，让前台经理把房间窗户打开通风，这才合适了。也巧，30楼的行政酒廊在这期间开放了，这两天躲在楼上看风景，喝下午茶，真是太好了。', '["https://dimg04.c-ctrip.com/images/0236m12000chhvslh4D2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000chhwyhs019A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000chhwm6b002A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000chhsf4bA25E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000chhr0ly8C3F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000chhyb8m1A67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000chi2ccyCC78_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000chhu2ik4AFF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000chhw3r3C98F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-31', '花园大床房', '大床房', '情侣出游', 157, 0, 114, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68028542e3c98b0941766164', '酒店服务很好，室外花园很惬意！出来就有地铁站，对面就是友谊商店很方便', '["https://dimg04.c-ctrip.com/images/0234912000df5xagh64ED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000df5puhzF21B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000df5z7ayA321_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-15', '花园双床房', '双床房', '商务出差', 34, 0, 3, 6, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('68028542e3c98b0941766165', '房间很干净', '["https://dimg04.c-ctrip.com/images/0230s12000enga365D0D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000engb0vm784F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000eng819z2E50_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-02', '红棉双床套房', '套房', '朋友出游', 5, 0, 16, 3, '["卫生状况"]'::jsonb, '卫生状况', NULL, NULL),
('68028542e3c98b0941766167', '绝对大气的酒店！淘金地铁站出来步行三分钟就到，出行极方便。附近有广州酒家和点都德，还有糖水店，餐饮极方便。', '["https://dimg04.c-ctrip.com/images/0231s12000d3odfmwDCF0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000d3oclcl2059_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-01', '花园双床房', '双床房', '家庭亲子', 53, 0, 17, 8, '["交通便利性","周边配套"]'::jsonb, '交通便利性', '周边配套', NULL),
('68028542e3c98b0941766169', '房间挺好的，酒店也很漂亮。但那天晚上半夜有人门口打电话吵到我睡觉了很不高兴。后来跟携程反馈了才处理好', '["https://dimg04.c-ctrip.com/images/0236z12000dqz6cpc16FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000dqz5mfmB751_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-22', '花园双床房', '双床房', '家庭亲子', 50, 0, 40, 6, '["安静程度","前台服务"]'::jsonb, '安静程度', '前台服务', NULL),
('68028542e3c98b094176616a', '自带瀑布花园的宝藏酒店，大堂布满鲜花，巨幅红楼梦贴金壁画金碧辉煌，气派华贵；旋转楼梯相当出片，后花园小桥流水，岩石飞瀑，体验感爆棚。', '["https://dimg04.c-ctrip.com/images/0232o12000df878rxF4B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000df86ooaCC30_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000df8614bC756_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000df86li9950B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000df85lxi88B7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-03-15', '花园双床房', '双床房', '朋友出游', 66, 0, 115, 9, '["公共设施","整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL),
('68028542e3c98b094176616c', '订之前好担心会设备陈旧，原来是我多虑了，值得下次再来', '["https://dimg04.c-ctrip.com/images/0232v12000dfybzy434A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-18', '红棉大床套房', '套房', '商务出差', 26, 0, 4, 5, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68028542e3c98b094176616d', '第一批的白金五星酒店，设施虽然有些旧了，服务很好。如果晚上行政酒廊可以看到外面的夜景，因该更惬意哦。', '["https://dimg04.c-ctrip.com/images/0235312000d25srrq9817_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000d265loxDCC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000d25oe5vC243_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000d25nowf8452_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-27', '花园双床房', '双床房', '朋友出游', 50, 0, 17, 6, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68028542e3c98b094176616e', '非常满意的一次入住，酒店方面没有因为客人提出的房间升级而板着面孔加钱的要求？前台小姐姐周到，耐心而且热情，尽量满足客人的需求，其实升级房型看似酒店损失，而实际上，客人的好评及口口相传比广告效益更好，这是格局长远的表现，看看前台办理入住的盛况？说明了酒店领导的眼光！感谢你们，我们还会再见！', '["https://dimg04.c-ctrip.com/images/0232g12000cjtzhhb2056_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000cjttg5d1974_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-10', '花园双床房', '双床房', '朋友出游', 144, 0, 22, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b094176616f', '服务很好，订了三晚，后面两天给我升级了房型，非常感谢！酒店的花园和博物馆也很有看头，女儿很喜欢，天天要去逛花园', '["https://dimg04.c-ctrip.com/images/0232r12000cy0eqbf6DBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000cy0864a2927_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000cy0bvk6E9A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000cy0c1y41500_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000cy0ddly4353_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-15', '花园大床房', '大床房', '家庭亲子', 55, 0, 10, 7, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('68028542e3c98b0941766170', '房间重新装修过，还不错，就是浴缸摆放位置有点奇怪。初一早上有舞龙醒狮，很有氛围', '["https://dimg04.c-ctrip.com/images/0236512000diz05ky935E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-28', '粤韵大床套房', '套房', '家庭亲子', 39, 0, 11, 6, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68028542e3c98b0941766171', '酒店非常好，物有所值，餐厅也很好吃，服务人员态度都很好，入住的时候发小礼物和点心，房间干净，隔音也好，可以说性价比相当高，就是淋浴在浴缸里的，我不太喜欢，要是可以分离就好了。体验了游泳池，还有免费的零食和冰淇淋。酒店总体的设施好得不得了，很多机组入住，国庆期间也有很多人办酒席，花园很漂亮，有博物馆。
自助早餐说实话非常一般，但水平比一般的酒店要好，主要还是外面的早茶太好吃了，一下子就把很普通的酒店自助餐比下去了。有30f旋转餐厅和大厅的瀑布餐厅可以选，旋转餐厅有点头晕，还挺热，建议还是瀑布餐厅吧。', '["https://dimg04.c-ctrip.com/images/0233t12000ciyh0lq968D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000ciygr14A011_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234h12000ciy85pgFAFB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-06', '红棉双床套房', '套房', '商务出差', 251, 0, 4, 9, '["性价比","整体满意度","餐饮设施"]'::jsonb, '性价比', '整体满意度', '餐饮设施'),
('68028542e3c98b0941766172', '花园酒店，开业38年，经久不衰，大堂永远人庭若市，伴随着悠扬的钢琴声，那么的和谐高雅。此次专门接远道而归的家人，酒店的服务没有过分的热情，确也非常的周到和细致见内涵。房间由原定的红棉套房升级了到了新装修过的房型，床品舒适，床垫偏软，包裹性和承托性很好，一晚恬睡到天明。花园瀑布绿意盎然，锦鲤成群，是饭后的最佳去处。总体入住体验全家满意，值得再来。', '["https://dimg04.c-ctrip.com/images/0231912000cheao36D0F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000chef6024A95_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000ched5zk6D02_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000cheanx02A31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000cheal6y898D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000chec5md9D68_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-30', '红棉双床套房', '套房', '家庭亲子', 173, 0, 48, 9, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68028542e3c98b0941766178', '这个酒店是我在广州住过最舒服的酒店，位置好，服务好，早餐丰富，前台办理员nike很漂亮，很是温柔，下次还住这里。', '["https://dimg04.c-ctrip.com/images/0233n12000dyi5cfr4344_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000dyi3qj19C46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000dyhtpx064CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000dyhytfs5488_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-11', '城央绿意大床房', '大床房', '家庭亲子', 56, 0, 32, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68028542e3c98b0941766179', '干净，服务好', '["https://dimg04.c-ctrip.com/images/0233412000dmhi61241A1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-08', '花园大床房', '大床房', '朋友出游', 6, 0, 2, 3, '["卫生状况","前台服务","客房服务"]'::jsonb, '卫生状况', '前台服务', '客房服务'),
('68028542e3c98b094176617a', '房间干净整洁。
服务：特别满意，有需求都能及时得到回应，服务特别好！酒店服务很用心！', '["https://dimg04.c-ctrip.com/images/0230r12000d1susqz5BAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000d1ski7i88A2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-26', '城央绿意双床房', '双床房', '情侣出游', 42, 0, 9, 5, '["卫生状况","客房服务","整体满意度"]'::jsonb, '卫生状况', '客房服务', '整体满意度'),
('68028542e3c98b094176617b', '这次和家人到广州旅游，入住了广州花园酒店。在越秀区的花园酒店。正直广交会来往的顾客非常的多，尤其外国人士占了将近50%。虽然入住率很高，但是花园酒店的服务也是跟得上，在广交会期间每层都有服务人员。问好，帮你排忧解难。虽然设施略显成就，但是作为亚洲第二个拥有旋转餐厅的酒店。总体还是非常的不错。', '["https://dimg04.c-ctrip.com/images/0231j12000cfpnc0o787E_R_150_150_R5_Q70_D.webp","https://dimg04.c-ctrip.com/images/0236512000cfpp1jp4075_R_150_150_R5_Q70_D.webp"]'::jsonb, 4.7, 4, '2023-10-22', '花园双床房', '双床房', '朋友出游', 146, 0, 15, 7, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('68028542e3c98b094176617c', '一如既往的好，每次来广州的必选酒店！', '["https://dimg04.c-ctrip.com/images/0236b12000dckopkn6647_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-05', '花园大床房', '大床房', '商务出差', 18, 0, 4, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b094176617d', '花园酒店广州的白金五星酒店，前台服务也是白金五星，处处为宾客着想。岭南花园小桥流水拍照打卡，四楼的酒店博物馆值得参观。', '["https://dimg04.c-ctrip.com/images/0234m12000cr1u4oxC2FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000cr1q3rc8CAE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000cr1t43a6236_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000cr1s4mbAA54_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000cr1t937AE7A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-17', '花园双床房', '双床房', '情侣出游', 59, 0, 203, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b094176617f', '非常满意的，一如既往的喜欢。瀑布餐厅的早餐不错??整体服务态度真的可以', '["https://dimg04.c-ctrip.com/images/0232c12000d31r9ws83A1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-30', '花园大床房', '大床房', '商务出差', 35, 0, 84, 5, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68028542e3c98b0941766180', '1. 【入住问题】入住排队等了几乎半个小时，从来没见过酒店前台效率这么低的；前台黑脸，没有微笑，不匹配酒店形象。完全是冲着品牌过来的，也住了很多次，反复多次提出过建议，没有任何改进。另外，前台和我们说升级到粤韵，结果发现是红棉，想换成粤韵，在房间打了一个小时电话都没有回复，令人恼火。
2. 【房间状态】红棉很旧，连中国大酒店这种低价酒店都比这个新，有点不可思议。喜欢这家酒店的粤韵，如果不订粤韵，其实这家酒店并没有那么值得居住，宁愿选择旁边的凯宾斯基酒店。我们经常住酒店，觉得花园酒店真的是人员服务匹配不上档次，能有预算选择白天鹅的话，还是选择白天鹅吧。
3. 【服务综评】这家酒店自从因为瀑布餐厅火了之后，管理素质一直跟不上来，甚至有服务人员不尊重客户的情况，不过副总经理和总经理态度尚在，不至于让人失望。但作为超过20年的老客户，真的为这家酒店的管理水平叹息。
ps.第一张和最后一张图是花园酒店，中间几张是旁边那一家酒店，真的对比好大……（??）?其实我们真的很喜欢花园酒店的，毕竟已经开了这么多年，当年做服装生意的时候也是在这里发家的，我们也有情怀，包括身边的朋友，也是有情怀却实在很难为之买单。今天的花园物是人非，除了公共区域之外，其他真的很难夸出口，也不想昧着良心来刷一个好评。??', '["https://dimg04.c-ctrip.com/images/0230m12000clvob1q68E8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000clvujafC987_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000clvvqb444A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000clvnm0cCE97_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000clvo52jF28F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2023-11-20', '花园双床房', '双床房', '其他', 548, 0, 3, 9, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('68028542e3c98b0941766181', '非常满意住在花园酒店，帮我们升级了红棉大床房，房间有些旧但是都能满足需求，服务人员服务都很好，各方面都很满意。', '["https://dimg04.c-ctrip.com/images/0234312000cs6f2apBA35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000cs651eu624F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000cs6cq42CA2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000cs6682e59A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000cs6d5kc3898_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000cs6gfljD48C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000cs6c87j7EE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000cs6c87lC2F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000cs5zcqz0D66_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-22', '城央绿意大床房', '大床房', '家庭亲子', 55, 0, 79, 7, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68028542e3c98b0941766182', '房间中规中矩，毕竟是中国最早的五星级酒店之二，现代的设施该有的都有。外形和大堂的挑高和巨幅壁画大观园让人震撼，中间藻井一条巨龙盘旋很是带气场，八台电梯足以让贝律铭大师的远见卓识得以认证。没感到岁月的蹉跎，维护得不错??。只是在办理入住和退房的时候稍感迟缓，需要等待多时才能办理好，但酒店不愧为国内五星级的黄埔军校，前台外语溜溜哒，耐心解释入住情况，可能也是办理迟缓的主要原因。住客多为老外，门童为巴基斯坦人，每个楼层都有服务员在电梯口恭候，特别感谢21楼服务员JoJo的热情接待，对问题反馈能及时解决。但酒店服务热线0号有时拨通了无人接听需要改进。小孩的洗漱用品没特别配备，有点遗憾。在旋转餐厅喝下午茶??时碰到了一个美籍华人，他告诉我自己常住花园酒店已有18年，虽然有天河一众奢华酒店，但他情有独钟，也是对酒店服务的认可，非常难得。', '["https://dimg04.c-ctrip.com/images/0236p12000cpmcy6s28C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000cpmc3fzF6C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000cpmcs9v40AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-10', '花园大床房', '大床房', '家庭亲子', 367, 0, 100, 9, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('68028542e3c98b0941766183', '花园酒店名符其实，地理位置优越，服务品质甚好！', '["https://dimg04.c-ctrip.com/images/0231012000d8sj5s9A4F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000d8seu0l3F98_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-19', '红棉大床套房', '套房', '朋友出游', 23, 0, 107, 5, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68028542e3c98b0941766184', '进入金碧辉煌的大堂，眼睛一亮，一幅镶金壁画《红楼梦》值得赞叹！高大圣诞树烘托节日气氛，前台服务特好，值得称赞。', '["https://dimg04.c-ctrip.com/images/0235r12000cqna9a51057_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000cqmzqqe51D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000cqna9a91400_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000cqn61vsE720_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-15', '红棉双床套房', '套房', '情侣出游', 55, 0, 203, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b0941766185', '广州花园酒店环境很优美，入住很舒适，一旦反应问题就会及时处理和解决。', '["https://dimg04.c-ctrip.com/images/0232812000d2urya07E03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000d2usir24AAF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000d2un9jc35BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-30', '红棉双床套房', '套房', '家庭亲子', 34, 0, 10, 6, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68028542e3c98b0941766186', '房间和服务都非常好，30楼的旋转餐厅非常给力，可以俯瞰整个广州城。健身房和游泳池也很高级，真正是商务家庭出游的好住处', '["https://dimg04.c-ctrip.com/images/0235a12000cpq8r6a7507_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000cpq8r71C219_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000cpq8r7o6E6D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-11', '花园大床房', '大床房', '商务出差', 58, 0, 15, 8, '["餐饮设施","公共设施","整体满意度"]'::jsonb, '餐饮设施', '公共设施', '整体满意度')
 ON CONFLICT (_id) DO NOTHING;
